using UnityEngine;
using UnityEditor;

public class Script
{
    public static string Main()
    {
        if (!System.IO.Directory.Exists(Application.dataPath + "/Items"))
            AssetDatabase.CreateFolder("Assets", "Items");
        if (!System.IO.Directory.Exists(Application.dataPath + "/Items/Weapons"))
            AssetDatabase.CreateFolder("Assets/Items", "Weapons");

        CreateSword("IronSword",   "Iron Sword",   25f);
        CreateSword("SteelSword",  "Steel Sword",  45f);
        CreateSword("PlasmaSword", "Plasma Sword", 70f);

        AssetDatabase.SaveAssets();
        AssetDatabase.Refresh();
        return "Created Iron (25 dmg), Steel (45 dmg), Plasma (70 dmg) sword ItemData assets in Assets/Items/Weapons/";
    }

    static void CreateSword(string fileName, string displayName, float damage)
    {
        var path = "Assets/Items/Weapons/" + fileName + ".asset";
        var existing = AssetDatabase.LoadAssetAtPath<ItemData>(path);
        if (existing != null)
        {
            existing.weaponDamage = damage;
            EditorUtility.SetDirty(existing);
            return;
        }

        var item = ScriptableObject.CreateInstance<ItemData>();
        item.itemName = displayName;
        item.stackable = false;
        item.maxStack = 1;
        var so = new SerializedObject(item);
        so.FindProperty("itemType").enumValueIndex = (int)ItemType.Weapon;
        so.FindProperty("weaponDamage").floatValue = damage;
        so.FindProperty("itemName").stringValue = displayName;
        so.FindProperty("stackable").boolValue = false;
        so.FindProperty("maxStack").intValue = 1;
        so.ApplyModifiedPropertiesWithoutUndo();
        AssetDatabase.CreateAsset(item, path);
    }
}
